    $val = (Get-ItemProperty -Path 'HKLM:\SOFTWARE\Policies\Microsoft\Windows\System' -Name 'AllowDomainPINLogon' -ErrorAction SilentlyContinue).AllowDomainPINLogon
    $status = if ($val -eq 0) { 'Pass' } else { 'Fail' }
    $findings.Add((New-Finding `
        -StigId       'WN11-CC-000370' `
        -Title        'The convenience PIN for Windows 11 must be disabled.' `
        -Severity     'CAT_II' `
        -Description  'This policy controls whether a domain user can sign in using a convenience PIN to prevent enabling (Password Stuffer). false <SeverityOverrideGuida' `
        -Check        'Registry: HKLM:\SOFTWARE\Policies\Microsoft\Windows\System -> AllowDomainPINLogon' `
        -Fix          'Disable the convenience PIN sign-in. To correct this, configure the policy value for Computer Configuration >> Administrative Templates >> System >> Logon >> Set `"Turn on convenience PIN sign-in`" to' `
        -PassCriteria 'Value = 0' `
        -Status       $status `
        -Evidence     "AllowDomainPINLogon = $(if (`$null -ne `$val) { `$val } else { 'NOT SET' })"
    ))
} catch {
    $findings.Add((New-Finding 'WN11-CC-000370' 'The convenience PIN for Windows 11 must be disabled.' 'CAT_II' '' '' '' '' 'Error' $_.ToString()))
}
